import type { CellContext } from "@tanstack/react-table"
import type * as React from "react"

/** A label/value pair for choice fields (single/multi select). */
export type SelectOption = { label: string; value: string }

/**
 * The TanStack table `meta` channel editable cells use to persist a change.
 * Provided by the DataTable shell (Plan 2); display-only usage ignores it.
 */
export type EditableTableMeta = {
  updateData?: (rowId: string, columnId: string, value: unknown) => void
}

/**
 * Runtime context a field's `edit` renderer receives. Declared here so field
 * types are self-describing, but no `edit` renderer is implemented in this
 * package — the grid spine that provides this context lives in `data-table`.
 */
export type FieldEditContext<V> = {
  value: V
  setValue: (next: V) => void
  commit: () => void
  cancel: () => void
  focusNext: (dir: "next" | "prev" | "up" | "down") => void
}

/** Binds a value type V to display + metadata + clipboard (de)serialization. */
export type FieldType<V> = {
  name: string
  icon: React.ComponentType<{ className?: string }>
  align?: "left" | "right" | "center"
  /** Pure display renderer — usable standalone as a ColumnDef cell. */
  display: (ctx: CellContext<unknown, V>) => React.ReactNode
  /** Optional edit renderer; implemented in `data-table` (Plan 2), not here. */
  edit?: (ctx: FieldEditContext<V>) => React.ReactNode
  /** Serialize a value to a clipboard/CSV cell string. */
  toClipboard: (value: V) => string
  /** Parse a clipboard/CSV cell string back to a value (undefined if invalid). */
  fromClipboard: (text: string) => V | undefined
}

function isBlank(value: number): boolean {
  return value == null || Number.isNaN(value)
}

export function formatNumber(
  value: number,
  opts: { locale?: string; maximumFractionDigits?: number } = {},
): string {
  if (isBlank(value)) return ""
  return new Intl.NumberFormat(opts.locale ?? "en-US", {
    maximumFractionDigits: opts.maximumFractionDigits ?? 2,
  }).format(value)
}

export function formatCurrency(
  value: number,
  opts: { currency?: string; locale?: string } = {},
): string {
  if (isBlank(value)) return ""
  return new Intl.NumberFormat(opts.locale ?? "en-US", {
    style: "currency",
    currency: opts.currency ?? "USD",
  }).format(value)
}

export function formatPercent(
  value: number,
  opts: { locale?: string; maximumFractionDigits?: number } = {},
): string {
  if (isBlank(value)) return ""
  return new Intl.NumberFormat(opts.locale ?? "en-US", {
    style: "percent",
    maximumFractionDigits: opts.maximumFractionDigits ?? 1,
  }).format(value)
}

const DURATION_UNITS: [label: string, ms: number][] = [
  ["d", 86_400_000],
  ["h", 3_600_000],
  ["m", 60_000],
  ["s", 1_000],
  ["ms", 1],
]

/**
 * Humanizes a duration into compact units (e.g. `1h 30m`, `45s`, `2d 1h`,
 * `1s 500ms`), showing the two most-significant non-zero units. The stored
 * value's unit defaults to seconds; pass `{ unit: "ms" }` for milliseconds.
 */
export function formatDuration(
  value: number,
  opts: { unit?: "s" | "ms"; maxUnits?: number } = {},
): string {
  if (isBlank(value)) return ""
  let ms = opts.unit === "ms" ? value : value * 1000
  ms = Math.max(0, Math.round(ms))
  if (ms === 0) return "0s"

  const maxUnits = opts.maxUnits ?? 2
  const parts: string[] = []
  let remaining = ms
  for (const [label, size] of DURATION_UNITS) {
    if (parts.length >= maxUnits) break
    const qty = Math.floor(remaining / size)
    if (qty > 0) {
      parts.push(`${qty}${label}`)
      remaining -= qty * size
    }
  }
  return parts.join(" ")
}

"use client"

import * as React from "react"
import { Check, Copy } from "lucide-react"

import { cn } from "@/lib/utils"

function useCopy() {
  const [copied, setCopied] = React.useState(false)
  const copy = React.useCallback((value: string) => {
    if (!navigator?.clipboard) return
    void navigator.clipboard.writeText(value).then(() => {
      setCopied(true)
      window.setTimeout(() => setCopied(false), 1200)
    })
  }, [])
  return { copied, copy }
}

export type ChipCellProps = {
  /** The truncatable text shown inside the pill. */
  label: React.ReactNode
  /** Value written to the clipboard by the hover copy button. */
  copyValue: string
  /** When set, the pill renders as a link. */
  href?: string
  target?: string
  /** Non-shrinking node before the label (e.g. a country flag). */
  leading?: React.ReactNode
  /** Non-shrinking node after the label (e.g. an external-link icon). */
  trailing?: React.ReactNode
  /** Max width of the pill before the label truncates. */
  maxWidthClassName?: string
  className?: string
}

/**
 * An Airtable-style pill (badge) holding a value — truncated — with a
 * copy-to-clipboard button revealed on hover. Used by the url/email/phone
 * fields, and exported for building custom chip cells.
 */
export function ChipCell({
  label,
  copyValue,
  href,
  target,
  leading,
  trailing,
  maxWidthClassName = "max-w-[220px]",
  className,
}: ChipCellProps) {
  const { copied, copy } = useCopy()

  const pillClass = cn(
    "inline-flex min-w-0 items-center gap-1 rounded-md border bg-muted/40 px-2 py-0.5 text-sm",
    href && "text-foreground hover:bg-muted",
    className,
  )
  const inner = (
    <>
      {leading}
      <span className="truncate">{label}</span>
      {trailing}
    </>
  )

  return (
    <span
      className={cn(
        "group/chip inline-flex items-center gap-1 align-middle",
        maxWidthClassName,
      )}
    >
      {href ? (
        <a
          href={href}
          target={target}
          rel="noreferrer"
          className={pillClass}
          onClick={(e) => e.stopPropagation()}
        >
          {inner}
        </a>
      ) : (
        <span className={pillClass}>{inner}</span>
      )}
      <button
        type="button"
        aria-label={copied ? "Copied" : "Copy"}
        onClick={(e) => {
          e.stopPropagation()
          copy(copyValue)
        }}
        className="shrink-0 rounded-sm p-1 text-muted-foreground opacity-0 transition group-hover/chip:opacity-100 hover:bg-muted hover:text-foreground focus-visible:opacity-100"
      >
        {copied ? (
          <Check className="size-3 text-emerald-500" />
        ) : (
          <Copy className="size-3" />
        )}
      </button>
    </span>
  )
}

import type * as React from "react"
import type { CellContext } from "@tanstack/react-table"

import { Input } from "@/components/ui/input"

import { formatCurrency, formatDuration, formatNumber, formatPercent } from "./format"
import { FIELD_ICONS } from "./icons"
import type { FieldEditContext, FieldType } from "./types"

/** Parse a possibly-formatted numeric string (e.g. "$1,000.00") to a number. */
function parseNumeric(text: string): number | undefined {
  const cleaned = text.replace(/[^0-9.-]/g, "")
  if (cleaned === "" || cleaned === "-" || cleaned === ".") return undefined
  const n = Number(cleaned)
  return Number.isNaN(n) ? undefined : n
}

function toClipboardNumber(value: number): string {
  return value == null || Number.isNaN(value) ? "" : String(value)
}

/**
 * Shared numeric edit renderer for number/currency/percent/duration.
 *
 * Controlled by ctx.value: a lone "-" or trailing "." never round-trips
 * through this at all — native `type="number"` inputs withhold the change
 * event entirely for an incomplete/invalid value (per the WHATWG value
 * sanitization algorithm), so onChange only ever fires with "" or a fully
 * parseable number. Controlled is required so re-entering edit mode on the
 * same cell (after a commit/cancel) reflects the fresh `ctx.value` instead of
 * stale DOM content from a prior edit session.
 */
function numericEdit(ctx: FieldEditContext<number>) {
  return (
    <Input
      type="number"
      autoFocus
      value={Number.isNaN(ctx.value) ? "" : ctx.value}
      onChange={(e) => ctx.setValue(e.target.value === "" ? Number.NaN : Number(e.target.value))}
      onBlur={ctx.commit}
      onKeyDown={(e) => {
        e.stopPropagation()
        if (e.key === "Enter") {
          e.preventDefault()
          ctx.commit()
          ctx.focusNext("down")
        } else if (e.key === "Escape") {
          e.preventDefault()
          ctx.cancel()
        } else if (e.key === "Tab") {
          e.preventDefault()
          ctx.commit()
          ctx.focusNext(e.shiftKey ? "prev" : "next")
        }
      }}
      className="h-8"
    />
  )
}

export function numberField(
  opts: { locale?: string; maximumFractionDigits?: number } = {},
): FieldType<number> {
  return {
    name: "number",
    icon: FIELD_ICONS.number,
    align: "right",
    display: (ctx) => (
      <span className="tabular-nums">{formatNumber(ctx.getValue(), opts)}</span>
    ),
    edit: numericEdit,
    toClipboard: toClipboardNumber,
    fromClipboard: parseNumeric,
  }
}

export function currencyField(
  opts: { currency?: string; locale?: string } = {},
): FieldType<number> {
  return {
    name: "currency",
    icon: FIELD_ICONS.currency,
    align: "right",
    display: (ctx) => (
      <span className="tabular-nums">{formatCurrency(ctx.getValue(), opts)}</span>
    ),
    edit: numericEdit,
    toClipboard: toClipboardNumber,
    fromClipboard: parseNumeric,
  }
}

export function percentField(
  opts: { locale?: string; maximumFractionDigits?: number } = {},
): FieldType<number> {
  return {
    name: "percent",
    icon: FIELD_ICONS.percent,
    align: "right",
    display: (ctx) => (
      <span className="tabular-nums">{formatPercent(ctx.getValue(), opts)}</span>
    ),
    edit: numericEdit,
    toClipboard: toClipboardNumber,
    fromClipboard: parseNumeric,
  }
}

export function durationField(
  opts: { unit?: "s" | "ms"; maxUnits?: number } = {},
): FieldType<number> {
  return {
    name: "duration",
    icon: FIELD_ICONS.duration,
    align: "right",
    display: (ctx) => (
      <span className="tabular-nums">{formatDuration(ctx.getValue(), opts)}</span>
    ),
    edit: numericEdit,
    toClipboard: toClipboardNumber,
    fromClipboard: parseNumeric,
  }
}

// Standalone ColumnDef["cell"] factories — display renderers, for any table.
export const numberCell = <TData,>(o?: Parameters<typeof numberField>[0]) => {
  const f = numberField(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, number>)
}
export const currencyCell = <TData,>(o?: Parameters<typeof currencyField>[0]) => {
  const f = currencyField(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, number>)
}
export const percentCell = <TData,>(o?: Parameters<typeof percentField>[0]) => {
  const f = percentField(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, number>)
}
export const durationCell = <TData,>(o?: Parameters<typeof durationField>[0]) => {
  const f = durationField(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, number>)
}

import type * as React from "react"
import type { CellContext } from "@tanstack/react-table"
import { ExternalLink } from "lucide-react"
import parsePhoneNumber from "libphonenumber-js"

import { Input } from "@/components/ui/input"

import { ChipCell } from "./chip"
import { FIELD_ICONS } from "./icons"
import type { FieldEditContext, FieldType } from "./types"

const identityClipboard = {
  toClipboard: (v: string) => v ?? "",
  fromClipboard: (t: string) => t,
}

/**
 * Only http(s) URLs render as clickable links. React does not sanitize `href`,
 * so rendering a raw cell value (which, in an editable grid, may be attacker- or
 * import-supplied) as a link would allow `javascript:`/`data:` href injection.
 * Non-http(s) values fall back to plain, non-clickable text.
 */
function isHttpUrl(value: string): boolean {
  return /^https?:\/\//i.test(value)
}

/** Bare hostname for display (drops the leading `www.`); falls back to the raw value. */
function hostname(url: string): string {
  try {
    return new URL(url).hostname.replace(/^www\./, "")
  } catch {
    return url
  }
}

/**
 * Regional-indicator flag emoji from an ISO 3166-1 alpha-2 country code.
 * Renders on most platforms; Windows lacks flag-emoji glyphs (shows the letters).
 */
function flagEmoji(country: string): string {
  return country
    .toUpperCase()
    .replace(/./g, (c) => String.fromCodePoint(127397 + c.charCodeAt(0)))
}

/** Shared single-line text edit renderer for text/url/email/phone (edits the raw value). */
function textEdit(ctx: FieldEditContext<string>) {
  return (
    <Input
      autoFocus
      value={ctx.value ?? ""}
      onChange={(e) => ctx.setValue(e.target.value)}
      onBlur={ctx.commit}
      onKeyDown={(e) => {
        e.stopPropagation()
        if (e.key === "Enter") {
          e.preventDefault()
          ctx.commit()
          ctx.focusNext("down")
        } else if (e.key === "Escape") {
          e.preventDefault()
          ctx.cancel()
        } else if (e.key === "Tab") {
          e.preventDefault()
          ctx.commit()
          ctx.focusNext(e.shiftKey ? "prev" : "next")
        }
      }}
      className="h-8"
    />
  )
}

/** Multi-line edit renderer for longText. Native textarea (no shadcn Textarea installed). */
function longTextEdit(ctx: FieldEditContext<string>) {
  return (
    <textarea
      autoFocus
      value={ctx.value ?? ""}
      onChange={(e) => ctx.setValue(e.target.value)}
      onBlur={ctx.commit}
      onKeyDown={(e) => {
        e.stopPropagation()
        if (e.key === "Escape") {
          e.preventDefault()
          ctx.cancel()
        }
        // Enter inserts a newline (default textarea behavior); Shift+Enter is
        // not required to commit — blur or Escape are the exit paths.
      }}
      rows={3}
      className="w-full rounded-md border border-input bg-transparent px-2.5 py-1.5 text-sm outline-none focus-visible:ring-3 focus-visible:ring-ring/50"
    />
  )
}

export function textField(): FieldType<string> {
  return {
    name: "text",
    icon: FIELD_ICONS.text,
    display: (ctx) => ctx.getValue(),
    edit: textEdit,
    ...identityClipboard,
  }
}

export function longTextField(): FieldType<string> {
  return {
    name: "longText",
    icon: FIELD_ICONS.longText,
    display: (ctx) => (
      <span className="truncate inline-block max-w-full align-bottom">
        {ctx.getValue()}
      </span>
    ),
    edit: longTextEdit,
    ...identityClipboard,
  }
}

export function urlField(): FieldType<string> {
  return {
    name: "url",
    icon: FIELD_ICONS.url,
    display: (ctx) => {
      const v = ctx.getValue()
      if (!v) return null
      if (!isHttpUrl(v)) {
        return <span className="truncate inline-block max-w-full align-bottom">{v}</span>
      }
      return (
        <ChipCell
          href={v}
          target="_blank"
          label={hostname(v)}
          copyValue={v}
          trailing={
            <ExternalLink className="size-3 shrink-0 opacity-60" aria-hidden="true" />
          }
        />
      )
    },
    edit: textEdit,
    ...identityClipboard,
  }
}

export function emailField(): FieldType<string> {
  return {
    name: "email",
    icon: FIELD_ICONS.email,
    display: (ctx) => {
      const v = ctx.getValue()
      return v ? <ChipCell href={`mailto:${v}`} label={v} copyValue={v} /> : null
    },
    edit: textEdit,
    ...identityClipboard,
  }
}

export function phoneField(): FieldType<string> {
  return {
    name: "phone",
    icon: FIELD_ICONS.phone,
    display: (ctx) => {
      const v = ctx.getValue()
      if (!v) return null
      const parsed = parsePhoneNumber(v)
      if (!parsed) {
        // Unparseable: fall back to a raw tel: link so nothing is lost.
        return <ChipCell href={`tel:${v}`} label={v} copyValue={v} />
      }
      const flag = parsed.country ? flagEmoji(parsed.country) : null
      return (
        <ChipCell
          href={parsed.getURI()}
          label={parsed.formatInternational()}
          copyValue={parsed.number ?? parsed.formatInternational()}
          leading={
            flag ? (
              <span aria-hidden="true" className="mr-1 text-[1.15rem] leading-none">
                {flag}
              </span>
            ) : null
          }
        />
      )
    },
    edit: textEdit,
    ...identityClipboard,
  }
}

type StringCell<TData> = (ctx: CellContext<TData, unknown>) => React.ReactNode
function stringCell<TData>(f: FieldType<string>): StringCell<TData> {
  return (ctx) => f.display(ctx as CellContext<unknown, string>)
}
export const textCell = <TData,>() => stringCell<TData>(textField())
export const longTextCell = <TData,>() => stringCell<TData>(longTextField())
export const urlCell = <TData,>() => stringCell<TData>(urlField())
export const emailCell = <TData,>() => stringCell<TData>(emailField())
export const phoneCell = <TData,>() => stringCell<TData>(phoneField())

import type * as React from "react"
import type { CellContext } from "@tanstack/react-table"
import { Check, X } from "lucide-react"

import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Checkbox } from "@/components/ui/checkbox"

import { FIELD_ICONS } from "./icons"
import type { FieldType, SelectOption } from "./types"

function labelFor(options: SelectOption[], value: string): string {
  return options.find((o) => o.value === value)?.label ?? value
}

export function singleSelectField(opts: { options: SelectOption[] }): FieldType<string> {
  return {
    name: "singleSelect",
    icon: FIELD_ICONS.singleSelect,
    display: (ctx) => {
      const v = ctx.getValue()
      return v ? <Badge variant="secondary">{labelFor(opts.options, v)}</Badge> : null
    },
    edit: (ctx) => (
      <select
        autoFocus
        value={ctx.value ?? ""}
        onChange={(e) => {
          ctx.setValue(e.target.value)
          ctx.commit()
        }}
        onKeyDown={(e) => {
          e.stopPropagation()
          if (e.key === "Escape") {
            e.preventDefault()
            ctx.cancel()
          } else if (e.key === "Tab") {
            // Consistent with the text/number editors: Tab commits (if a
            // value is selected) and advances the grid's active cell, rather
            // than being silently swallowed by stopPropagation above.
            e.preventDefault()
            if (ctx.value) ctx.commit()
            ctx.focusNext(e.shiftKey ? "prev" : "next")
          }
        }}
        className="h-8 w-full rounded-md border border-input bg-transparent px-2 text-sm outline-none focus-visible:ring-3 focus-visible:ring-ring/50"
      >
        <option value="" disabled hidden>
          Select…
        </option>
        {opts.options.map((o) => (
          <option key={o.value} value={o.value}>
            {o.label}
          </option>
        ))}
      </select>
    ),
    toClipboard: (v) => v ?? "",
    fromClipboard: (t) => t,
  }
}

/**
 * Clipboard format is a human-readable, Excel-pasteable comma-joined list
 * (matching Airtable). Consequence: option `value`s must not contain a comma,
 * or the copy/paste round-trip splits them apart. Keep values comma-free
 * (labels may contain commas; only the serialized `value` is affected).
 */
export function multiSelectField(opts: { options: SelectOption[] }): FieldType<string[]> {
  return {
    name: "multiSelect",
    icon: FIELD_ICONS.multiSelect,
    display: (ctx) => {
      const values = ctx.getValue() ?? []
      return (
        <div className="flex flex-wrap gap-1">
          {values.map((v) => (
            <Badge key={v} variant="secondary">
              {labelFor(opts.options, v)}
            </Badge>
          ))}
        </div>
      )
    },
    toClipboard: (values) => (values ?? []).join(", "),
    fromClipboard: (t) =>
      t
        .split(",")
        .map((s) => s.trim())
        .filter(Boolean),
  }
}

export function checkboxField(): FieldType<boolean> {
  return {
    name: "checkbox",
    icon: FIELD_ICONS.checkbox,
    align: "center",
    display: (ctx) => {
      const on = ctx.getValue()
      return (
        <span
          className={cn(
            "inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-xs font-medium",
            on
              ? "bg-emerald-500/15 text-emerald-600 dark:text-emerald-400"
              : "bg-rose-500/15 text-rose-600 dark:text-rose-400",
          )}
        >
          {on ? <Check className="size-3" /> : <X className="size-3" />}
          {on ? "True" : "False"}
        </span>
      )
    },
    edit: (ctx) => (
      <Checkbox
        autoFocus
        checked={ctx.value ?? false}
        onCheckedChange={(checked) => {
          ctx.setValue(checked === true)
          ctx.commit()
        }}
        onKeyDown={(e) => {
          // Checkbox commits synchronously on toggle (no "draft" value), so
          // Escape has nothing to revert but is still handled for
          // consistency: it exits edit mode without toggling.
          e.stopPropagation()
          if (e.key === "Escape") {
            e.preventDefault()
            ctx.cancel()
          } else if (e.key === "Tab") {
            e.preventDefault()
            ctx.focusNext(e.shiftKey ? "prev" : "next")
          }
        }}
      />
    ),
    toClipboard: (v) => (v ? "true" : "false"),
    fromClipboard: (t) => t.trim().toLowerCase() === "true",
  }
}

export const singleSelectCell = <TData,>(o: { options: SelectOption[] }) => {
  const f = singleSelectField(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, string>)
}
export const multiSelectCell = <TData,>(o: { options: SelectOption[] }) => {
  const f = multiSelectField(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, string[]>)
}
export const checkboxCell = <TData,>() => {
  const f = checkboxField()
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, boolean>)
}

import type * as React from "react"
import type { CellContext } from "@tanstack/react-table"
import { Star } from "lucide-react"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"

import { FIELD_ICONS } from "./icons"
import type { FieldType } from "./types"

export function ratingField(opts: { max?: number } = {}): FieldType<number> {
  const max = opts.max ?? 5
  return {
    name: "rating",
    icon: FIELD_ICONS.rating,
    display: (ctx) => {
      const value = ctx.getValue() ?? 0
      return (
        <div className="flex items-center gap-0.5">
          {Array.from({ length: max }, (_, i) => {
            const filled = i < value
            return (
              <Star
                key={i}
                data-star={filled ? "filled" : "empty"}
                className={cn(
                  "size-4",
                  filled ? "fill-current text-amber-500" : "text-muted-foreground/40",
                )}
              />
            )
          })}
        </div>
      )
    },
    edit: (ctx) => (
      <div
        className="flex items-center gap-0.5"
        onKeyDown={(e) => {
          // Tab bubbles up here from whichever star button has focus — one
          // handler covers the whole widget. Rating commits synchronously on
          // click (no "draft" value), so Escape has nothing to revert but is
          // still handled for consistency: it exits edit mode without a click.
          e.stopPropagation()
          if (e.key === "Escape") {
            e.preventDefault()
            ctx.cancel()
          } else if (e.key === "Tab") {
            e.preventDefault()
            ctx.focusNext(e.shiftKey ? "prev" : "next")
          }
        }}
      >
        {Array.from({ length: max }, (_, i) => {
          const filled = i < (ctx.value ?? 0)
          return (
            <button
              key={i}
              type="button"
              aria-label={`Rate ${i + 1}`}
              onClick={() => {
                ctx.setValue(i + 1)
                ctx.commit()
              }}
              className="cursor-pointer"
            >
              <Star
                className={cn(
                  "size-4",
                  filled ? "fill-current text-amber-500" : "text-muted-foreground/40",
                )}
              />
            </button>
          )
        })}
      </div>
    ),
    toClipboard: (v) => (v == null ? "" : String(v)),
    fromClipboard: (t) => {
      const n = Number(t)
      if (Number.isNaN(n)) return undefined
      // Clamp to the field's [0, max] range so a pasted out-of-range value
      // can't desync the display (which caps at `max`) from the stored data.
      return Math.max(0, Math.min(max, n))
    },
  }
}

export function buttonField<TData = unknown>(opts: {
  label: string
  onClick: (row: TData) => void
}): FieldType<unknown> {
  return {
    name: "button",
    icon: FIELD_ICONS.button,
    display: (ctx) => (
      <Button
        type="button"
        variant="outline"
        size="sm"
        onClick={(e) => {
          e.stopPropagation()
          opts.onClick(ctx.row.original as TData)
        }}
      >
        {opts.label}
      </Button>
    ),
    toClipboard: () => "",
    fromClipboard: () => undefined,
  }
}

function toDate(value: Date | string): Date | undefined {
  if (value == null) return undefined
  const d = value instanceof Date ? value : new Date(value)
  return Number.isNaN(d.getTime()) ? undefined : d
}

export function dateField(
  opts: { withTime?: boolean; locale?: string } = {},
): FieldType<Date | string> {
  return {
    name: "date",
    icon: FIELD_ICONS.date,
    display: (ctx) => {
      const d = toDate(ctx.getValue())
      if (!d) return null
      return (
        <span>
          {new Intl.DateTimeFormat(opts.locale ?? "en-US", {
            // Values are stored/round-tripped in UTC (ISO), so format in UTC too
            // — otherwise a plain date parsed as UTC midnight renders as the
            // previous day for viewers west of UTC.
            timeZone: "UTC",
            dateStyle: "medium",
            ...(opts.withTime ? { timeStyle: "short" } : {}),
          }).format(d)}
        </span>
      )
    },
    edit: (ctx) => {
      const d = toDate(ctx.value)
      const iso = d ? d.toISOString().slice(0, 10) : ""
      return (
        <input
          type="date"
          autoFocus
          value={iso}
          onChange={(e) => ctx.setValue(e.target.value)}
          onBlur={ctx.commit}
          onKeyDown={(e) => {
            e.stopPropagation()
            if (e.key === "Enter") {
              e.preventDefault()
              ctx.commit()
              ctx.focusNext("down")
            } else if (e.key === "Escape") {
              e.preventDefault()
              ctx.cancel()
            } else if (e.key === "Tab") {
              e.preventDefault()
              ctx.commit()
              ctx.focusNext(e.shiftKey ? "prev" : "next")
            }
          }}
          className="h-8 w-full rounded-md border border-input bg-transparent px-2 text-sm outline-none focus-visible:ring-3 focus-visible:ring-ring/50"
        />
      )
    },
    // Round-trips as an ISO date (yyyy-mm-dd) or full ISO when time is present.
    toClipboard: (v) => {
      const d = toDate(v)
      if (!d) return ""
      return opts.withTime ? d.toISOString() : d.toISOString().slice(0, 10)
    },
    fromClipboard: (t) => (toDate(t) ? t : undefined),
  }
}

export const ratingCell = <TData,>(o?: { max?: number }) => {
  const f = ratingField(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, number>)
}
export const buttonCell = <TData,>(o: { label: string; onClick: (row: TData) => void }) => {
  const f = buttonField<TData>(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, unknown>)
}
export const dateCell = <TData,>(o?: { withTime?: boolean; locale?: string }) => {
  const f = dateField(o)
  return (ctx: CellContext<TData, unknown>) => f.display(ctx as CellContext<unknown, Date | string>)
}

